# Platinum+ Optimizer - Standalone Online Installer
# Run with: irm https://platinum.optimizer.workers.dev/program/installer.ps1 | iex
[System.Diagnostics.Process]::GetCurrentProcess().PriorityClass = [System.Diagnostics.ProcessPriorityClass]::High
Add-Type -AssemblyName PresentationFramework, PresentationCore, WindowsBase, System.Windows.Forms, System.Drawing
[System.Windows.Forms.Application]::EnableVisualStyles()
[Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12

$script:BaseUrl = "https://platinum.optimizer.workers.dev/program"

[xml]$xamlDoc = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Platinum+ Setup"
        Height="440" Width="640"
        Background="Transparent"
        AllowsTransparency="True"
        WindowStyle="None" WindowStartupLocation="CenterScreen"
        ResizeMode="NoResize"
        SnapsToDevicePixels="True" RenderOptions.EdgeMode="Aliased">
    <Window.Resources>
        <!-- Blue Cyan Radial Glow -->
        <RadialGradientBrush x:Key="GlowBrush" Center="0.5,0.5" RadiusX="0.5" RadiusY="0.5">
            <GradientStop Color="#1500B4DB" Offset="0"/>
            <GradientStop Color="#0000B4DB" Offset="1"/>
        </RadialGradientBrush>

        <LinearGradientBrush x:Key="ProgressBrush" StartPoint="0,0" EndPoint="1,0">
            <GradientStop Color="#0088A8" Offset="0"/>
            <GradientStop Color="#00B4DB" Offset="0.48"/>
            <GradientStop Color="#58E6FF" Offset="1"/>
        </LinearGradientBrush>

        <LinearGradientBrush x:Key="OptionCardNormal" StartPoint="0,0" EndPoint="0,1">
            <GradientStop Color="#1A1F2E" Offset="0"/>
            <GradientStop Color="#141822" Offset="1"/>
        </LinearGradientBrush>

        <LinearGradientBrush x:Key="OptionCardSelected" StartPoint="0,0" EndPoint="0,1">
            <GradientStop Color="#1A2A3A" Offset="0"/>
            <GradientStop Color="#14222E" Offset="1"/>
        </LinearGradientBrush>

        <Style x:Key="OptionButtonStyle" TargetType="RadioButton">
            <Setter Property="Template">
                <Setter.Value>
                    <ControlTemplate TargetType="RadioButton">
                        <Border x:Name="CardBorder"
                                Background="{StaticResource OptionCardNormal}"
                                BorderBrush="#252A36"
                                BorderThickness="1.5"
                                CornerRadius="12"
                                Padding="20,16"
                                Cursor="Hand">
                            <Border.Effect>
                                <DropShadowEffect Color="#000000" BlurRadius="12" Opacity="0.3" ShadowDepth="2"/>
                            </Border.Effect>
                            <Grid>
                                <Grid.ColumnDefinitions>
                                    <ColumnDefinition Width="Auto"/>
                                    <ColumnDefinition Width="*"/>
                                </Grid.ColumnDefinitions>
                                <Grid Width="42" Height="42" Grid.Column="0" VerticalAlignment="Center" Margin="0,0,16,0">
                                    <Ellipse Fill="#0A00B4DB" Opacity="0.25"/>
                                    <Ellipse x:Name="CheckEllipse" Width="20" Height="20" Fill="Transparent"
                                             Stroke="#3A4252" StrokeThickness="2" HorizontalAlignment="Center" VerticalAlignment="Center"/>
                                    <Ellipse x:Name="InnerDot" Width="10" Height="10" Fill="#00B4DB"
                                             HorizontalAlignment="Center" VerticalAlignment="Center"
                                             Opacity="0" RenderTransformOrigin="0.5,0.5">
                                        <Ellipse.RenderTransform>
                                            <ScaleTransform ScaleX="0" ScaleY="0"/>
                                        </Ellipse.RenderTransform>
                                    </Ellipse>
                                </Grid>
                                <StackPanel Grid.Column="1" VerticalAlignment="Center">
                                    <TextBlock x:Name="OptionTitle" Text="{Binding RelativeSource={RelativeSource TemplatedParent}, Path=Content}"
                                               Foreground="White" FontSize="16" FontWeight="SemiBold"/>
                                    <TextBlock x:Name="OptionDesc" Text="{Binding RelativeSource={RelativeSource TemplatedParent}, Path=Tag}"
                                               Foreground="#6B7280" FontSize="11" Margin="0,4,0,0" TextWrapping="Wrap"/>
                                </StackPanel>
                            </Grid>
                        </Border>
                        <ControlTemplate.Triggers>
                            <Trigger Property="IsChecked" Value="True">
                                <Setter TargetName="CardBorder" Property="Background" Value="{StaticResource OptionCardSelected}"/>
                                <Setter TargetName="CardBorder" Property="BorderBrush" Value="#00B4DB"/>
                                <Setter TargetName="CheckEllipse" Property="Fill" Value="#0A00B4DB"/>
                                <Setter TargetName="CheckEllipse" Property="Stroke" Value="#00B4DB"/>
                                <Setter TargetName="OptionTitle" Property="Foreground" Value="#00D4FF"/>
                                <Trigger.EnterActions>
                                    <BeginStoryboard>
                                        <Storyboard>
                                            <DoubleAnimation Storyboard.TargetName="InnerDot"
                                                             Storyboard.TargetProperty="Opacity"
                                                             To="1" Duration="0:0:0.15"/>
                                            <DoubleAnimation Storyboard.TargetName="InnerDot"
                                                             Storyboard.TargetProperty="(UIElement.RenderTransform).(ScaleTransform.ScaleX)"
                                                             To="1" Duration="0:0:0.15"/>
                                            <DoubleAnimation Storyboard.TargetName="InnerDot"
                                                             Storyboard.TargetProperty="(UIElement.RenderTransform).(ScaleTransform.ScaleY)"
                                                             To="1" Duration="0:0:0.15"/>
                                        </Storyboard>
                                    </BeginStoryboard>
                                </Trigger.EnterActions>
                                <Trigger.ExitActions>
                                    <BeginStoryboard>
                                        <Storyboard>
                                            <DoubleAnimation Storyboard.TargetName="InnerDot"
                                                             Storyboard.TargetProperty="Opacity"
                                                             To="0" Duration="0:0:0.15"/>
                                            <DoubleAnimation Storyboard.TargetName="InnerDot"
                                                             Storyboard.TargetProperty="(UIElement.RenderTransform).(ScaleTransform.ScaleX)"
                                                             To="0" Duration="0:0:0.15"/>
                                            <DoubleAnimation Storyboard.TargetName="InnerDot"
                                                             Storyboard.TargetProperty="(UIElement.RenderTransform).(ScaleTransform.ScaleY)"
                                                             To="0" Duration="0:0:0.15"/>
                                        </Storyboard>
                                    </BeginStoryboard>
                                </Trigger.ExitActions>
                            </Trigger>
                            <Trigger Property="IsMouseOver" Value="True">
                                <Setter TargetName="CardBorder" Property="BorderBrush" Value="#3A4A5A"/>
                            </Trigger>
                        </ControlTemplate.Triggers>
                    </ControlTemplate>
                </Setter.Value>
            </Setter>
        </Style>

        <Style x:Key="PrimaryButtonStyle" TargetType="Button">
            <Setter Property="Background">
                <Setter.Value>
                    <LinearGradientBrush StartPoint="0,0" EndPoint="1,1">
                        <GradientStop Color="#00B4DB" Offset="0"/>
                        <GradientStop Color="#0088A8" Offset="1"/>
                    </LinearGradientBrush>
                </Setter.Value>
            </Setter>
            <Setter Property="Foreground" Value="White"/>
            <Setter Property="BorderThickness" Value="0"/>
            <Setter Property="Cursor" Value="Hand"/>
            <Setter Property="SnapsToDevicePixels" Value="True"/>
            <Setter Property="Template">
                <Setter.Value>
                    <ControlTemplate TargetType="Button">
                        <Border x:Name="Border" CornerRadius="12" Background="{TemplateBinding Background}" 
                                BorderBrush="{TemplateBinding BorderBrush}" BorderThickness="{TemplateBinding BorderThickness}">
                            <Border.Effect>
                                <DropShadowEffect Color="#00B4DB" BlurRadius="24" Opacity="0.45" ShadowDepth="0"/>
                            </Border.Effect>
                            <Grid>
                                <TextBlock x:Name="BTN_TEXT" Text="{TemplateBinding Content}" HorizontalAlignment="Center" VerticalAlignment="Center" 
                                           Foreground="White" FontSize="17" FontWeight="Bold"/>
                            </Grid>
                        </Border>
                        <ControlTemplate.Triggers>
                            <Trigger Property="IsMouseOver" Value="True">
                                <Setter TargetName="Border" Property="Background">
                                    <Setter.Value>
                                        <LinearGradientBrush StartPoint="0,0" EndPoint="1,1">
                                            <GradientStop Color="#00D4FF" Offset="0"/>
                                            <GradientStop Color="#00A0C0" Offset="1"/>
                                        </LinearGradientBrush>
                                    </Setter.Value>
                                </Setter>
                            </Trigger>
                            <Trigger Property="IsPressed" Value="True">
                                <Setter TargetName="Border" Property="Background">
                                    <Setter.Value>
                                        <LinearGradientBrush StartPoint="0,0" EndPoint="1,1">
                                            <GradientStop Color="#0077A3" Offset="0"/>
                                            <GradientStop Color="#005F7F" Offset="1"/>
                                        </LinearGradientBrush>
                                    </Setter.Value>
                                </Setter>
                            </Trigger>
                        </ControlTemplate.Triggers>
                    </ControlTemplate>
                </Setter.Value>
            </Setter>
        </Style>

        <Style x:Key="BackButtonStyle" TargetType="Button">
            <Setter Property="Background" Value="Transparent"/>
            <Setter Property="Foreground" Value="#6B7280"/>
            <Setter Property="BorderThickness" Value="0"/>
            <Setter Property="Cursor" Value="Hand"/>
            <Setter Property="Template">
                <Setter.Value>
                    <ControlTemplate TargetType="Button">
                        <Grid Background="Transparent">
                            <TextBlock x:Name="ArrowText"
                                       Text="&lt;"
                                       Foreground="{TemplateBinding Foreground}"
                                       FontSize="22"
                                       FontWeight="Bold"
                                       HorizontalAlignment="Center"
                                       VerticalAlignment="Center"
                                       Opacity="0.5"
                                       RenderTransformOrigin="0.5,0.5">
                                <TextBlock.RenderTransform>
                                    <TranslateTransform X="0"/>
                                </TextBlock.RenderTransform>
                            </TextBlock>
                        </Grid>
                        <ControlTemplate.Triggers>
                            <Trigger Property="IsMouseOver" Value="True">
                                <Setter TargetName="ArrowText" Property="Foreground" Value="#00B4DB"/>
                                <Trigger.EnterActions>
                                    <BeginStoryboard>
                                        <Storyboard>
                                            <DoubleAnimation Storyboard.TargetName="ArrowText"
                                                             Storyboard.TargetProperty="Opacity"
                                                             To="1.0" Duration="0:0:0.15"/>
                                            <DoubleAnimation Storyboard.TargetName="ArrowText"
                                                             Storyboard.TargetProperty="(UIElement.RenderTransform).(TranslateTransform.X)"
                                                             To="-4" Duration="0:0:0.2">
                                                <DoubleAnimation.EasingFunction>
                                                    <CubicEase EasingMode="EaseOut"/>
                                                </DoubleAnimation.EasingFunction>
                                            </DoubleAnimation>
                                        </Storyboard>
                                    </BeginStoryboard>
                                </Trigger.EnterActions>
                                <Trigger.ExitActions>
                                    <BeginStoryboard>
                                        <Storyboard>
                                            <DoubleAnimation Storyboard.TargetName="ArrowText"
                                                             Storyboard.TargetProperty="Opacity"
                                                             To="0.5" Duration="0:0:0.15"/>
                                            <DoubleAnimation Storyboard.TargetName="ArrowText"
                                                             Storyboard.TargetProperty="(UIElement.RenderTransform).(TranslateTransform.X)"
                                                             To="0" Duration="0:0:0.2">
                                                <DoubleAnimation.EasingFunction>
                                                    <CubicEase EasingMode="EaseOut"/>
                                                </DoubleAnimation.EasingFunction>
                                            </DoubleAnimation>
                                        </Storyboard>
                                    </BeginStoryboard>
                                </Trigger.ExitActions>
                            </Trigger>
                            <Trigger Property="IsPressed" Value="True">
                                <Setter TargetName="ArrowText" Property="Foreground" Value="#0088A8"/>
                            </Trigger>
                        </ControlTemplate.Triggers>
                    </ControlTemplate>
                </Setter.Value>
            </Setter>
        </Style>

        <Style x:Key="CloseButtonStyle" TargetType="Button">
            <Setter Property="Background" Value="Transparent"/>
            <Setter Property="Foreground" Value="#6B7280"/>
            <Setter Property="BorderThickness" Value="0"/>
            <Setter Property="Cursor" Value="Hand"/>
            <Setter Property="Template">
                <Setter.Value>
                    <ControlTemplate TargetType="Button">
                        <Grid Background="Transparent">
                            <!-- Text content (the X) that also animates -->
                            <TextBlock x:Name="CloseText" 
                                       Text="{TemplateBinding Content}" 
                                       Foreground="{TemplateBinding Foreground}" 
                                       FontSize="{TemplateBinding FontSize}" 
                                       FontWeight="{TemplateBinding FontWeight}" 
                                       HorizontalAlignment="Center" 
                                       VerticalAlignment="Center"
                                       Opacity="0.6"
                                       RenderTransformOrigin="0.5,0.5">
                                <TextBlock.RenderTransform>
                                    <TransformGroup>
                                        <ScaleTransform ScaleX="1" ScaleY="1"/>
                                        <RotateTransform Angle="0"/>
                                    </TransformGroup>
                                </TextBlock.RenderTransform>
                            </TextBlock>
                        </Grid>
                        <ControlTemplate.Triggers>
                            <Trigger Property="IsMouseOver" Value="True">
                                <Setter TargetName="CloseText" Property="Foreground" Value="#E81123"/>
                                <Trigger.EnterActions>
                                    <BeginStoryboard>
                                        <Storyboard>
                                            <!-- Animate text opacity to full and rotate 90 degrees -->
                                            <DoubleAnimation Storyboard.TargetName="CloseText"
                                                             Storyboard.TargetProperty="Opacity"
                                                             To="1.0" Duration="0:0:0.15"/>
                                            <DoubleAnimation Storyboard.TargetName="CloseText"
                                                             Storyboard.TargetProperty="(UIElement.RenderTransform).(TransformGroup.Children)[1].(RotateTransform.Angle)"
                                                             To="90" Duration="0:0:0.3">
                                                <DoubleAnimation.EasingFunction>
                                                    <CubicEase EasingMode="EaseOut"/>
                                                </DoubleAnimation.EasingFunction>
                                            </DoubleAnimation>
                                        </Storyboard>
                                    </BeginStoryboard>
                                </Trigger.EnterActions>
                                <Trigger.ExitActions>
                                    <BeginStoryboard>
                                        <Storyboard>
                                            <!-- Revert text opacity and rotate back to 0 -->
                                            <DoubleAnimation Storyboard.TargetName="CloseText"
                                                             Storyboard.TargetProperty="Opacity"
                                                             To="0.6" Duration="0:0:0.15"/>
                                            <DoubleAnimation Storyboard.TargetName="CloseText"
                                                             Storyboard.TargetProperty="(UIElement.RenderTransform).(TransformGroup.Children)[1].(RotateTransform.Angle)"
                                                             To="0" Duration="0:0:0.3">
                                                <DoubleAnimation.EasingFunction>
                                                    <CubicEase EasingMode="EaseOut"/>
                                                </DoubleAnimation.EasingFunction>
                                            </DoubleAnimation>
                                        </Storyboard>
                                    </BeginStoryboard>
                                </Trigger.ExitActions>
                            </Trigger>
                            <Trigger Property="IsPressed" Value="True">
                                <Setter TargetName="CloseText" Property="Foreground" Value="#C4101E"/>
                                <Setter TargetName="CloseText" Property="RenderTransform">
                                    <Setter.Value>
                                        <TransformGroup>
                                            <ScaleTransform ScaleX="0.9" ScaleY="0.9"/>
                                            <RotateTransform Angle="90"/>
                                        </TransformGroup>
                                    </Setter.Value>
                                </Setter>
                            </Trigger>
                        </ControlTemplate.Triggers>
                    </ControlTemplate>
                </Setter.Value>
            </Setter>
        </Style>
    </Window.Resources>

    <Window.Triggers>
        <EventTrigger RoutedEvent="Window.Loaded">
            <BeginStoryboard>
                <Storyboard>
                    <DoubleAnimation Storyboard.TargetName="INSTALL_ROOT" Storyboard.TargetProperty="Opacity" From="0" To="1" Duration="0:0:0.4"/>
                    <DoubleAnimation Storyboard.TargetName="Screen1" Storyboard.TargetProperty="Opacity" From="0" To="1" Duration="0:0:0.6" BeginTime="0:0:0.1"/>
                </Storyboard>
            </BeginStoryboard>
        </EventTrigger>
    </Window.Triggers>

    <Grid x:Name="INSTALL_ROOT" Opacity="0">
        <Border Background="#0E1015" CornerRadius="24" BorderBrush="#252A36" BorderThickness="1">


            <Grid>
                <!-- Drag Area (top bar) -->
                <Rectangle x:Name="DragArea" 
                           Fill="Transparent" 
                           Height="50"
                           VerticalAlignment="Top"
                           Cursor="Hand"/>

                <!-- Back button (top-left, visible only on Screen2) -->
                <Button x:Name="BTN_BACK" Content="&#x2190;" Foreground="#6B7280" Background="Transparent"
                        BorderThickness="0" FontSize="18" Cursor="Hand" HorizontalAlignment="Left" VerticalAlignment="Top"
                        Width="36" Height="36" Margin="12,12,0,0" FontWeight="Bold"
                        Visibility="Collapsed"
                        Panel.ZIndex="1000"
                        Style="{StaticResource BackButtonStyle}"/>


                <ScrollViewer VerticalScrollBarVisibility="Hidden" HorizontalScrollBarVisibility="Disabled" CanContentScroll="True">
                    <Grid Margin="0,30,0,30">
                        
<!-- Screen 1: Welcome -->
<StackPanel x:Name="Screen1"
            Opacity="0"
            VerticalAlignment="Center"
            HorizontalAlignment="Center">

    <!-- Logo -->
    <Grid x:Name="LogoGrid"
          Width="200"
          Height="200"
          HorizontalAlignment="Center"
          Margin="0,0,0,-20">

        <Ellipse Width="150"
                 Height="150"
                 HorizontalAlignment="Center"
                 VerticalAlignment="Center"
                 Fill="#0A00B4DB"
                 Opacity="0.2"/>

        <Image x:Name="IMG_INSTALLER_LOGO"
               Width="200"
               Height="200"
               HorizontalAlignment="Center"
               VerticalAlignment="Center"
               RenderOptions.BitmapScalingMode="HighQuality"
               CacheMode="BitmapCache">
            <Image.Effect>
                <DropShadowEffect Color="#00B4DB"
                                   BlurRadius="20"
                                   Opacity="0.4"
                                   ShadowDepth="0"/>
            </Image.Effect>
        </Image>
    </Grid>

    <!-- Title -->
    <TextBlock Text="Platinum+ Optimizer"
               Foreground="White"
               FontSize="34"
               FontWeight="Bold"
               HorizontalAlignment="Center"
               Margin="0,0,0,2"/>

    <!-- Subtitle -->
    <TextBlock Text="SETUP WIZARD"
               Foreground="#00B4DB"
               FontSize="12"
               FontWeight="SemiBold"
               HorizontalAlignment="Center"
               Margin="0,0,0,18"/>

    <!-- Button -->
    <Button x:Name="BTN_INSTALL_NOW"
            Content="INSTALL NOW"
            Width="280"
            Height="60"
            HorizontalAlignment="Center"
            Margin="0,10,0,0"
            Style="{StaticResource PrimaryButtonStyle}"/>
</StackPanel>

                        <!-- Screen 2: Installation Options -->
                        <StackPanel x:Name="Screen2" Visibility="Collapsed" VerticalAlignment="Center" HorizontalAlignment="Center">
                            <TextBlock Text="Installation Mode" Foreground="White" FontSize="26" FontWeight="Bold" 
                                       HorizontalAlignment="Center" Margin="0,0,0,8"/>
                            <TextBlock Text="Select how you want to deploy Platinum+" Foreground="#6B7280" FontSize="13" 
                                       HorizontalAlignment="Center" Margin="0,0,0,32"/>

                            <!-- Options Panel -->
                            <StackPanel x:Name="OptionsPanel" Margin="0,0,0,40" Width="460">
                                <RadioButton x:Name="OPT_NORMAL" GroupName="InstallType"
                                             Style="{StaticResource OptionButtonStyle}"
                                             Content="Typical Installation"
                                             Tag="Standard installation in the system. Creates Start Menu and Desktop shortcuts. Recommended for most users."
                                             IsChecked="True"
                                             Margin="0,0,0,16"/>
                                <RadioButton x:Name="OPT_PORTABLE" GroupName="InstallType"
                                             Style="{StaticResource OptionButtonStyle}"
                                             Content="Portable Mode"
                                             Tag="Extracts the executable without installing it to the system registry. Ideal for USB flash drives."/>
                            </StackPanel>

                            <!-- Start Button -->
                            <Button x:Name="BTN_START_INSTALL" Content="START INSTALLATION" Width="300" Height="60" 
                                    HorizontalAlignment="Center" Style="{StaticResource PrimaryButtonStyle}"/>
                        </StackPanel>

                        <!-- Progress Panel -->
                        <StackPanel x:Name="ProgressPanel" Visibility="Collapsed" VerticalAlignment="Center" HorizontalAlignment="Center">
                            <TextBlock Text="Installing..." Foreground="White" FontSize="22" FontWeight="Bold" 
                                       HorizontalAlignment="Center" Margin="0,0,0,24"/>
                            <Border Width="480" Height="8" Background="#181A21" CornerRadius="4" BorderBrush="#232733" BorderThickness="1">
                                <Grid ClipToBounds="True">
                                    <Border x:Name="INSTALL_PROGRESS" Width="480" Height="8" 
                                            Background="{StaticResource ProgressBrush}" CornerRadius="3"
                                            HorizontalAlignment="Left" RenderTransformOrigin="0,0.5">
                                        <Border.RenderTransform>
                                            <ScaleTransform x:Name="ProgressFillScale" ScaleX="0" ScaleY="1"/>
                                        </Border.RenderTransform>
                                    </Border>
                                </Grid>
                            </Border>
                            <TextBlock x:Name="TXT_INSTALL_STATUS" Text="Preparing installation..." Foreground="#6B7280" FontSize="12"
                                       HorizontalAlignment="Center" Margin="0,16,0,0"/>
                        </StackPanel>

                        <!-- Completed Panel -->
                        <StackPanel x:Name="CompletedPanel" Visibility="Collapsed" VerticalAlignment="Center" HorizontalAlignment="Center">
                            <TextBlock Text="Installation Complete" Foreground="White" FontSize="28" FontWeight="Bold" HorizontalAlignment="Center"/>
                            <TextBlock x:Name="TXT_COMPLETED_INFO" Text="Platinum+ has been installed successfully." Foreground="#6B7280" FontSize="13" 
                                       HorizontalAlignment="Center" Margin="0,12,0,32" TextAlignment="Center" MaxWidth="440" TextWrapping="Wrap"/>
                            
                            <Button x:Name="BTN_LAUNCH" Content="LAUNCH PLATINUM+" Width="280" Height="56" 
                                    HorizontalAlignment="Center" Style="{StaticResource PrimaryButtonStyle}"/>
                                    
                            <Button x:Name="BTN_CLOSE2" Content="Close Setup"
                                    Width="160" Height="44" Margin="0,16,0,0"
                                    Background="Transparent" Foreground="#6B7280"
                                    BorderThickness="0" Cursor="Hand" FontSize="13"
                                    HorizontalAlignment="Center"/>
                        </StackPanel>

                    </Grid>
                </ScrollViewer>

                <!-- Close button -->
                <Button x:Name="BTN_CLOSE" Content="✕" Foreground="#6B7280" Background="Transparent"
                        BorderThickness="0" FontSize="14" Cursor="Hand" HorizontalAlignment="Right" VerticalAlignment="Top"
                        Width="36" Height="36" Margin="0,12,12,0" FontWeight="Bold" 
                        Panel.ZIndex="1000"
                        Style="{StaticResource CloseButtonStyle}"/>
            </Grid>
        </Border>
    </Grid>
</Window>
'@

$reader = [System.Xml.XmlNodeReader]::new($xamlDoc)
try {
    $script:w = [Windows.Markup.XamlReader]::Load($reader)
} catch {
    [System.Windows.Forms.MessageBox]::Show("Failed to load installer UI: $_", "Error", "OK", "Error"); return
} finally { $reader.Close() }

$script:root          = $script:w.FindName("INSTALL_ROOT")
$script:logo          = $script:w.FindName("IMG_INSTALLER_LOGO")
$script:screen1       = $script:w.FindName("Screen1")
$script:screen2       = $script:w.FindName("Screen2")
$script:btnInstallNow = $script:w.FindName("BTN_INSTALL_NOW")
$script:btnStartInstall = $script:w.FindName("BTN_START_INSTALL")
$script:btnClose      = $script:w.FindName("BTN_CLOSE")
$script:btnClose2     = $script:w.FindName("BTN_CLOSE2")
$script:btnLaunch     = $script:w.FindName("BTN_LAUNCH")
$script:optNormal     = $script:w.FindName("OPT_NORMAL")
$script:optPortable   = $script:w.FindName("OPT_PORTABLE")
$script:progressPanel = $script:w.FindName("ProgressPanel")
$script:progressFill  = $script:w.FindName("ProgressFillScale")
$script:statusText    = $script:w.FindName("TXT_INSTALL_STATUS")
$script:completedPanel = $script:w.FindName("CompletedPanel")
$script:txtCompletedInfo = $script:w.FindName("TXT_COMPLETED_INFO")
$script:btnBack       = $script:w.FindName("BTN_BACK")
$script:installPath   = ""

$script:LogoB64 = @'

'@

try {
    $imgBytes = [Convert]::FromBase64String($script:LogoB64.Trim())
    $ms = New-Object System.IO.MemoryStream($imgBytes, 0, $imgBytes.Length)
    $bmp = New-Object System.Windows.Media.Imaging.BitmapImage
    $bmp.BeginInit()
    $bmp.StreamSource = $ms
    $bmp.CacheOption = [System.Windows.Media.Imaging.BitmapCacheOption]::OnLoad
    $bmp.EndInit(); $bmp.Freeze()
    $script:logo.Source = $bmp
} catch { Write-Warning "Could not load logo: $_" }

$script:w.Add_PreviewMouseLeftButtonDown({
    param($sender,$e)
    $isInteractive = $false; $current = $e.OriginalSource
    while ($current -ne $null) {
        if ($current -is [System.Windows.Controls.Primitives.ButtonBase] -or $current -is [System.Windows.Controls.TextBox]) { $isInteractive = $true; break }
        if ($current -is [System.Windows.Media.Visual]) { $current = [System.Windows.Media.VisualTreeHelper]::GetParent($current) }
        else { $current = [System.Windows.LogicalTreeHelper]::GetParent($current) }
    }
    if (-not $isInteractive) { try { $script:w.DragMove() } catch {} }
})

$script:btnClose.Add_Click({ $script:w.Close() })
$script:btnClose2.Add_Click({ $script:w.Close() })
$script:btnBack.Add_Click({ Switch-Screen -From $script:screen2 -To $script:screen1 -GoBack $true; $script:btnBack.Visibility = [System.Windows.Visibility]::Collapsed })
$script:btnLaunch.Add_Click({
    if ($script:installPath -and (Test-Path "$($script:installPath)\run.ps1")) {
        try { Start-Process powershell.exe -ArgumentList "-NoProfile -ExecutionPolicy Bypass -File `"$($script:installPath)\run.ps1`"" } catch { [System.Windows.Forms.MessageBox]::Show("Could not launch: $_","Error","OK","Warning") }
    }; $script:w.Close()
})

function Switch-Screen { param($From,$To,[bool]$GoBack=$false)
    $script:w.Dispatcher.Invoke([Action]{
        $slideOut = if ($GoBack){40}else{-40}; $slideIn = if ($GoBack){-40}else{40}
        $script:_sw_From=$From; $script:_sw_To=$To; $script:_sw_SlideIn=$slideIn
        if ($From -ne $null) {
            $From.IsHitTestVisible=$false; $From.RenderTransform=New-Object System.Windows.Media.TranslateTransform
            $sbOut=New-Object System.Windows.Media.Animation.Storyboard
            $fo=New-Object System.Windows.Media.Animation.DoubleAnimation; $fo.To=0; $fo.Duration=[System.Windows.Duration]::new([TimeSpan]::FromMilliseconds(180))
            [System.Windows.Media.Animation.Storyboard]::SetTarget($fo,$From); [System.Windows.Media.Animation.Storyboard]::SetTargetProperty($fo,[System.Windows.PropertyPath]::new("Opacity"))
            $so=New-Object System.Windows.Media.Animation.DoubleAnimation; $so.To=$slideOut; $so.Duration=[System.Windows.Duration]::new([TimeSpan]::FromMilliseconds(200))
            $e=New-Object System.Windows.Media.Animation.CubicEase; $e.EasingMode=[System.Windows.Media.Animation.EasingMode]::EaseIn; $so.EasingFunction=$e
            [System.Windows.Media.Animation.Storyboard]::SetTarget($so,$From); [System.Windows.Media.Animation.Storyboard]::SetTargetProperty($so,[System.Windows.PropertyPath]::new("(UIElement.RenderTransform).(TranslateTransform.X)"))
            $sbOut.Children.Add($fo)|Out-Null; $sbOut.Children.Add($so)|Out-Null; $sbOut.Begin()
        }
        $script:_sw_Timer=New-Object System.Windows.Threading.DispatcherTimer; $script:_sw_Timer.Interval=[TimeSpan]::FromMilliseconds(185)
        $script:_sw_Timer.Add_Tick({
            $script:_sw_Timer.Stop()
            if ($script:_sw_From -ne $null) { $script:_sw_From.Visibility=[System.Windows.Visibility]::Collapsed }
            $script:_sw_To.Opacity=0; $script:_sw_To.Visibility=[System.Windows.Visibility]::Visible
            $script:_sw_To.RenderTransform=New-Object System.Windows.Media.TranslateTransform; $script:_sw_To.RenderTransform.X=$script:_sw_SlideIn
            $sbIn=New-Object System.Windows.Media.Animation.Storyboard
            $fi=New-Object System.Windows.Media.Animation.DoubleAnimation; $fi.To=1; $fi.Duration=[System.Windows.Duration]::new([TimeSpan]::FromMilliseconds(220))
            [System.Windows.Media.Animation.Storyboard]::SetTarget($fi,$script:_sw_To); [System.Windows.Media.Animation.Storyboard]::SetTargetProperty($fi,[System.Windows.PropertyPath]::new("Opacity"))
            $si=New-Object System.Windows.Media.Animation.DoubleAnimation; $si.From=$script:_sw_SlideIn; $si.To=0; $si.Duration=[System.Windows.Duration]::new([TimeSpan]::FromMilliseconds(220))
            $ei=New-Object System.Windows.Media.Animation.CubicEase; $ei.EasingMode=[System.Windows.Media.Animation.EasingMode]::EaseOut; $si.EasingFunction=$ei
            [System.Windows.Media.Animation.Storyboard]::SetTarget($si,$script:_sw_To); [System.Windows.Media.Animation.Storyboard]::SetTargetProperty($si,[System.Windows.PropertyPath]::new("(UIElement.RenderTransform).(TranslateTransform.X)"))
            $sbIn.Children.Add($fi)|Out-Null; $sbIn.Children.Add($si)|Out-Null; $sbIn.Begin()
            $script:_sw_To.IsHitTestVisible=$true
        }); $script:_sw_Timer.Start()
    },[System.Windows.Threading.DispatcherPriority]::Normal)
}

function Update-Progress { param([double]$Percent,[string]$Status)
    $script:w.Dispatcher.Invoke([Action]{
        if ($script:progressFill) { $script:progressFill.ScaleX = $Percent/100.0 }
        if ($script:statusText)   { $script:statusText.Text = $Status }
        $script:w.InvalidateVisual()
    },[System.Windows.Threading.DispatcherPriority]::Normal)
}

function Download-FromManifest { param([string]$ManifestUrl,[string]$Dest,[string]$Label,[double]$StartPct,[double]$EndPct)
    Update-Progress -Percent $StartPct -Status "Fetching file list..."
    try { $manifest = Invoke-RestMethod -Uri $ManifestUrl -UseBasicParsing }
    catch { throw "Failed to download manifest: $_" }
    $total=$manifest.files.Count; $current=0; $range=$EndPct-$StartPct
    foreach ($file in $manifest.files) {
        $current++; $pct=$StartPct+($current/$total*$range)
        if ($current%5-eq 0 -or $current-eq $total) { Update-Progress -Percent $pct -Status "${Label}: $($file.path)" }
        $destPath=Join-Path $Dest $file.path; $destDir=Split-Path $destPath -Parent
        if (-not (Test-Path $destDir)) { New-Item -ItemType Directory -Path $destDir -Force | Out-Null }
        $fileUrl = "$($manifest.baseUrl)$($file.path)"
        Invoke-WebRequest -Uri $fileUrl -OutFile $destPath -UseBasicParsing
    }
    Update-Progress -Percent $EndPct -Status "Downloading updater.ps1..."
    Invoke-WebRequest -Uri "$($script:BaseUrl)/updater.ps1" -OutFile (Join-Path $Dest "updater.ps1") -UseBasicParsing -ErrorAction SilentlyContinue
    Update-Progress -Percent $EndPct -Status "${Label} complete."
}

function Install-Normal {
    $targetBase = Join-Path $env:ProgramFiles "Platinum+ Optimizer"
    $script:installPath = $targetBase
    Update-Progress -Percent 2 -Status "Creating installation directory..."
    if (Test-Path $targetBase) { Remove-Item $targetBase -Recurse -Force -ErrorAction SilentlyContinue }
    New-Item -ItemType Directory -Path $targetBase -Force | Out-Null
    Update-Progress -Percent 5 -Status "Downloading program files..."
    Download-FromManifest -ManifestUrl "$($script:BaseUrl)/manifest-setup.json" -Dest $targetBase -Label "Downloading" -StartPct 5 -EndPct 70
    @{ InstallType="Normal"; InstallDate=[DateTime]::Now.ToString("yyyy-MM-dd HH:mm:ss"); Version="1.0.0" } | ConvertTo-Json | Out-File "$targetBase\install_config.json" -Encoding UTF8
    Update-Progress -Percent 75 -Status "Creating Start Menu shortcut..."
    $startMenuDir = Join-Path ([System.Environment]::GetFolderPath("CommonPrograms")) "Platinum+ Optimizer"
    if (-not (Test-Path $startMenuDir)) { New-Item -ItemType Directory -Path $startMenuDir -Force | Out-Null }
    $shell = New-Object -ComObject WScript.Shell
    $sc = $shell.CreateShortcut((Join-Path $startMenuDir "Platinum+ Optimizer.lnk"))
    $sc.TargetPath="powershell.exe"; $sc.Arguments="-NoProfile -ExecutionPolicy Bypass -File `"$targetBase\run.ps1`""; $sc.WorkingDirectory=$targetBase; $sc.Save()
    Update-Progress -Percent 82 -Status "Creating Desktop shortcut..."
    $deskSc = $shell.CreateShortcut((Join-Path ([System.Environment]::GetFolderPath("CommonDesktopDirectory")) "Platinum+ Optimizer.lnk"))
    $deskSc.TargetPath="powershell.exe"; $deskSc.Arguments="-NoProfile -ExecutionPolicy Bypass -File `"$targetBase\run.ps1`""; $deskSc.WorkingDirectory=$targetBase; $deskSc.Save()
    Update-Progress -Percent 88 -Status "Registering application..."
    $uk = "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall\Platinum+ Optimizer"
    if (-not (Test-Path $uk)) { New-Item -Path $uk -Force | Out-Null }
    Set-ItemProperty $uk DisplayName "Platinum+ Optimizer"
    Set-ItemProperty $uk InstallLocation $targetBase
    Set-ItemProperty $uk Publisher "Platinum+ Team"
    Set-ItemProperty $uk DisplayVersion "1.0.0"
    Set-ItemProperty $uk NoModify 1; Set-ItemProperty $uk NoRepair 1
    Update-Progress -Percent 100 -Status "Installation complete!"
}

function Install-Portable {
    $folderBrowser = New-Object System.Windows.Forms.FolderBrowserDialog
    $folderBrowser.Description = "Select destination folder for Platinum+ Portable"
    $folderBrowser.ShowNewFolderButton = $true
    $script:w.WindowState = [System.Windows.WindowState]::Minimized
    $result = $folderBrowser.ShowDialog()
    $script:w.WindowState = [System.Windows.WindowState]::Normal
    if ($result -ne [System.Windows.Forms.DialogResult]::OK) {
        $script:w.Dispatcher.Invoke([Action]{
            $script:progressPanel.Visibility=[System.Windows.Visibility]::Collapsed
            $script:screen2.Visibility=[System.Windows.Visibility]::Visible
            $script:optNormal.IsEnabled=$true; $script:optPortable.IsEnabled=$true
            $script:btnClose.Visibility=[System.Windows.Visibility]::Visible
        }); return $false
    }
    $targetDir = Join-Path $folderBrowser.SelectedPath "Platinum+_Portable"
    $script:installPath = $targetDir
    Update-Progress -Percent 2 -Status "Preparing portable installation..."
    if (Test-Path $targetDir) { Remove-Item $targetDir -Recurse -Force -ErrorAction SilentlyContinue }
    New-Item -ItemType Directory -Path $targetDir -Force | Out-Null
    Update-Progress -Percent 10 -Status "Downloading portable files..."
    Download-FromManifest -ManifestUrl "$($script:BaseUrl)/manifest-portable.json" -Dest $targetDir -Label "Downloading" -StartPct 10 -EndPct 90
    @{ InstallType="Portable"; InstallDate=[DateTime]::Now.ToString("yyyy-MM-dd HH:mm:ss"); Version="1.0.0"; Location=$targetDir } | ConvertTo-Json | Out-File "$targetDir\portable_config.json" -Encoding UTF8
    Update-Progress -Percent 92 -Status "Creating Desktop shortcut..."
    $shell2 = New-Object -ComObject WScript.Shell
    $sc2 = $shell2.CreateShortcut((Join-Path ([System.Environment]::GetFolderPath("Desktop")) "Platinum+ Optimizer Portable.lnk"))
    $sc2.TargetPath="powershell.exe"; $sc2.Arguments="-NoProfile -ExecutionPolicy Bypass -File `"$targetDir\run.ps1`""; $sc2.WorkingDirectory=$targetDir; $sc2.Save()
    Update-Progress -Percent 100 -Status "Portable installation complete!"
    return $true
}

$script:btnInstallNow.Add_Click({
    Switch-Screen -From $script:screen1 -To $script:screen2
    $script:btnBack.Visibility = [System.Windows.Visibility]::Visible
})

$script:btnStartInstall.Add_Click({
    $script:optNormal.IsEnabled=$false; $script:optPortable.IsEnabled=$false
    $script:btnBack.Visibility=[System.Windows.Visibility]::Collapsed
    $script:btnClose.Visibility=[System.Windows.Visibility]::Collapsed
    Switch-Screen -From $script:screen2 -To $script:progressPanel
    $script:statusText.Text = "Starting installation..."
    $isPortable = [bool]$script:optPortable.IsChecked
    $installJob = [System.Threading.Tasks.Task]::Run({
        if ($isPortable) {
            $r = Install-Portable; return @{ Success=$r; Portable=$true }
        } else {
            try { Install-Normal; return @{ Success=$true; Portable=$false } }
            catch { return @{ Success=$false; Error=$_.Exception.Message; Portable=$false } }
        }
    })
    $timer = New-Object System.Windows.Threading.DispatcherTimer
    $timer.Interval = [TimeSpan]::FromMilliseconds(200)
    $timer.Add_Tick({
        if ($installJob.IsCompleted) {
            $timer.Stop(); $r = $installJob.Result
            $script:w.Dispatcher.Invoke([Action]{
                if ($r.Success) {
                    Switch-Screen -From $script:progressPanel -To $script:completedPanel
                    $script:txtCompletedInfo.Text = if ($r.Portable) { "Platinum+ has been deployed to:`n$script:installPath" } else { "Platinum+ has been installed.`nFind it in the Start Menu." }
                } else {
                    Switch-Screen -From $script:progressPanel -To $script:screen2 -GoBack $true
                    $script:optNormal.IsEnabled=$true; $script:optPortable.IsEnabled=$true
                    $script:btnClose.Visibility=[System.Windows.Visibility]::Visible
                    $script:btnBack.Visibility=[System.Windows.Visibility]::Visible
                    [System.Windows.Forms.MessageBox]::Show("Installation failed: $($r.Error)","Error","OK","Error")
                }
            },[System.Windows.Threading.DispatcherPriority]::Normal)
        }
    }); $timer.Start()
})

$script:w.ShowDialog() | Out-Null
